import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.Arrays;

public class SolutionTest {

    /**
     * Sorts both arrays and compares element by element.
     * This normalizes any unspecified ordering in the result.
     */
    private void assertSameElements(int[] expected, int[] actual) {
        assertEquals(expected.length, actual.length,
            "Expected " + expected.length + " elements but got " + actual.length);
        int[] sortedExp = Arrays.copyOf(expected, expected.length);
        int[] sortedAct = Arrays.copyOf(actual, actual.length);
        Arrays.sort(sortedExp);
        Arrays.sort(sortedAct);
        assertArrayEquals(sortedExp, sortedAct,
            "Multisets differ. Expected (sorted): " + Arrays.toString(sortedExp)
            + ", got (sorted): " + Arrays.toString(sortedAct));
    }

    @Test
    void classic() {
        int[] result = new Solution().topKLargest(new int[]{3, 2, 1, 5, 6, 4}, 3);
        assertSameElements(new int[]{4, 5, 6}, result);
    }

    @Test
    void topTwo() {
        int[] result = new Solution().topKLargest(new int[]{7, 10, 4, 3, 20, 15}, 2);
        assertSameElements(new int[]{15, 20}, result);
    }

    @Test
    void kEqualsLength() {
        // all elements are top-k
        int[] result = new Solution().topKLargest(new int[]{3, 1, 4, 1, 5}, 5);
        assertSameElements(new int[]{1, 1, 3, 4, 5}, result);
    }

    @Test
    void kEqualsOne() {
        // largest element only
        int[] result = new Solution().topKLargest(new int[]{9, 2, 7, 4, 6}, 1);
        assertSameElements(new int[]{9}, result);
    }

    @Test
    void singleElement() {
        int[] result = new Solution().topKLargest(new int[]{5}, 1);
        assertSameElements(new int[]{5}, result);
    }

    @Test
    void withDuplicatesInTopK() {
        // sorted: 1,2,3,5,5,8 => top-3: {5,5,8}
        int[] result = new Solution().topKLargest(new int[]{5, 1, 8, 3, 2, 5}, 3);
        assertSameElements(new int[]{5, 5, 8}, result);
    }

    @Test
    void allDuplicates() {
        // all same value — top-2 of 4 equal elements
        int[] result = new Solution().topKLargest(new int[]{6, 6, 6, 6}, 2);
        assertSameElements(new int[]{6, 6}, result);
    }
}
